SELECT instance_name
FROM instances
WHERE problem_type = 'non-linear';

SELECT COUNT(*) AS total_instances
FROM instances
WHERE problem_type = 'non-linear';

SELECT version
FROM solver_versions
WHERE version = '1.0';

SELECT solver_name
FROM solvers
WHERE solver_type = 'exact';

SELECT AVG(actual_runtime) AS average_runtime
FROM runtime_logs
WHERE machine_name = 'Machine1';

SELECT solver_name
FROM solvers
ORDER BY solver_name;
